let storiesData = [];
let currentStory = null;

document.addEventListener('DOMContentLoaded', () => {
    const nav = document.getElementById("navLinks");
    const icon = document.querySelector(".menu-icon");
    const btt = document.getElementById("backToTop");
    const countdownEl = document.getElementById("countdown");

    // --- 1. PRIORITY SCROLLSPY ---
function updateScrollSpy() {
    const scrollPos = window.scrollY || document.documentElement.scrollTop;
    const windowHeight = window.innerHeight;
    const docHeight = document.documentElement.scrollHeight;
    
    let current = "";
    const sections = document.querySelectorAll("section");

    // 1. Check if we are at the very bottom of the page
    // This forces FAQ to be active even if it's too short to hit the top
    if (scrollPos + windowHeight >= docHeight - 50) {
        current = "faqs"; // Or whatever your FAQ ID is
    } else {
        sections.forEach(section => {
            const sectionTop = section.offsetTop - 150; // 150px buffer for the header
            if (scrollPos >= sectionTop) {
                current = section.getAttribute("id");
            }
        });
    }

    const allLinks = document.querySelectorAll('#navLinks a, .dropbtn');
    
    allLinks.forEach(a => {
        a.classList.remove("active");
        const href = a.getAttribute("href");

        // Logic for "Greatest Stories" dropdown parent
        const storySections = ["video", "article", "gallery", "stories"];
        if (storySections.includes(current)) {
            // Check if it's the dropdown button or the link itself
            if (a.textContent.trim().includes("Stories") || a.classList.contains("dropbtn")) {
                a.classList.add("active");
            }
        } 
        
        // Standard match
        if (href === `#${current}`) {
            a.classList.add("active");
        }
    });
}

    window.addEventListener('scroll', () => {
        updateScrollSpy();
        if (window.pageYOffset > 300) btt.classList.add("visible");
        else btt.classList.remove("visible");
    });

    updateScrollSpy();

    // --- 2. MENU LOGIC (STABLE) ---
window.closeMenu = function() {
    nav.classList.remove("active");
    if (icon) icon.classList.remove("open");

    // ONLY hide the display if we are on a mobile/tablet screen
    if (window.innerWidth <= 1024) {
        setTimeout(() => { 
            if (!nav.classList.contains("active")) {
                nav.style.display = "none"; 
            }
        }, 500);
    } else {
        // Ensure desktop ALWAYS stays flex
        nav.style.display = "flex"; 
    }
};

    window.toggleMenu = function() {
        if (nav.classList.contains("active")) {
            window.closeMenu();
        } else {
            nav.style.display = "flex";
            setTimeout(() => {
                nav.classList.add("active");
                icon.classList.add("open");
            }, 10);
        }
    };

    window.toggleAccordion = function(event, menuId) {
        if (window.innerWidth <= 1024) {
            event.preventDefault();
            event.stopPropagation();
            const target = document.getElementById(menuId);
            document.querySelectorAll('.accordion-menu').forEach(m => {
                if (m.id !== menuId) m.classList.remove('show');
            });
            target.classList.toggle('show');
        }
    };

    nav.addEventListener('click', (e) => {
        if (e.target.tagName === 'A' && !e.target.classList.contains('dropbtn')) {
            window.closeMenu();
        }
    });

    // --- 3. COUNTDOWN (STABLE) ---
// Target date: June 16, 2026 (Adjust as needed)
const targetDate = new Date("June 16, 2026 00:00:00").getTime();

function updateCountdown() {
    const now = new Date().getTime();
    const diff = targetDate - now;

    if (diff <= 0) return;

    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
    const hours = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
    const mins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
    const secs = Math.floor((diff % (1000 * 60)) / 1000);

    handleFlip(document.querySelector("[data-days]"), days);
    handleFlip(document.querySelector("[data-hours]"), hours);
    handleFlip(document.querySelector("[data-minutes]"), mins);
    handleFlip(document.querySelector("[data-seconds]"), secs);
}

function handleFlip(cardEl, newValue) {
    const formatted = newValue < 10 ? `0${newValue}` : newValue;
    const topHalf = cardEl.querySelector(".static-top .number-wrapper");

    if (formatted == topHalf.innerText) return;

    // Update all number wrappers
    cardEl.querySelectorAll(".number-wrapper").forEach(el => {
        el.innerText = formatted;
    });

    cardEl.classList.remove("flipping");
    void cardEl.offsetWidth; 
    cardEl.classList.add("flipping");

    setTimeout(() => {
        cardEl.classList.remove("flipping");
    }, 600);
}

setInterval(updateCountdown, 1000);
updateCountdown();

const navbar = document.querySelector('.navbar');

    // Listen for the user scrolling
    window.addEventListener('scroll', () => {
        // If they scroll down more than 50 pixels...
        if (window.scrollY > 50) {
            navbar.classList.add('scrolled'); // Turn on the solid background
        } else {
            navbar.classList.remove('scrolled'); // Make it transparent again
        }
    });
});

// --- 4. DYNAMIC STORIES & BRIGHTCOVE LOGIC ---
async function loadStories() {
    try {
        const response = await fetch('stories.json');
        storiesData = await response.json();
        
        if (document.getElementById('filterType')) {
            handleCategoryChange(); 
        }
        // Load the very first story into the stage by default
        if(storiesData.length > 0) updatePreview(storiesData[0]);
    } catch (error) {
        console.error("Error loading stories:", error);
    }
}

window.handleCategoryChange = function() {
    const typeVal = document.getElementById('filterType').value;
    const speakerSelect = document.getElementById('filterSpeaker');
    if (!speakerSelect) return;
    
    speakerSelect.innerHTML = '';

    if (typeVal === 'article') {
        // 1. If they select Articles
        const articleOptions = [
            { val: 'all', text: 'All Articles' }, 
            { val: 'Pre-Event', text: 'Pre-Event Articles' },
            { val: 'Daily', text: 'Daily Articles' },
            { val: 'Post-Event', text: 'Post-Event Articles' }
        ];
        articleOptions.forEach(s => {
            const opt = document.createElement('option');
            opt.value = s.val; opt.innerHTML = s.text;
            speakerSelect.appendChild(opt);
        });

    } else if (typeVal === 'video') {
        // 2. If they select Videos (Changed from "else" to strictly "video")
        const videoOptions = [
            { val: 'all', text: 'All Videos' }, // Updated text to say All Videos
            { val: 'Teasers', text: 'Teasers' },
            { val: 'Invite', text: 'Invite Videos' },
            { val: 'Campaign', text: 'Campaign Videos' },
            { val: 'FoundersChief', text: 'Founders & Chief Dailies' },
            { val: 'Highlights', text: 'Daily Highlights' },
            { val: 'Post-Event', text: 'Post-Event Videos' }
        ];
        videoOptions.forEach(s => {
            const opt = document.createElement('option');
            opt.value = s.val; opt.innerHTML = s.text;
            speakerSelect.appendChild(opt);
        });

    } else {
        // 3. If they select "All Media" (typeVal === 'all')
        // We give them a generic "All Categories" option so the filter shows everything
        const allOptions = [
            { val: 'all', text: 'All Categories' }
        ];
        allOptions.forEach(s => {
            const opt = document.createElement('option');
            opt.value = s.val; opt.innerHTML = s.text;
            speakerSelect.appendChild(opt);
        });
    }
    
    // Now it runs your flawless filter code!
    applyFilters();
};

window.applyFilters = function() {
    // 1. Get the current values from the dropdowns
    const typeVal = document.getElementById('filterType').value;
    const speakerVal = document.getElementById('filterSpeaker').value;
    const dayVal = document.getElementById('filterDay').value;
    const resetBtn = document.getElementById('resetFilters');

    // 2. Handle Reset Button visibility
    if (resetBtn) {
        if (typeVal !== 'all' || speakerVal !== 'all' || dayVal !== 'all') {
            resetBtn.style.display = 'inline-block';
        } else {
            resetBtn.style.display = 'none';
        }
    }

    // 3. Filter the data (using the variables we just defined above)
    const filtered = storiesData.filter(item => {
        const matchType = (typeVal === 'all' || item.type === typeVal);
        const matchSpeaker = (speakerVal === 'all' || item.speaker === speakerVal);
        const matchDay = (dayVal === 'all' || item.day === dayVal);
        return matchType && matchSpeaker && matchDay;
    });

    // 4. Update the UI
    renderFilteredPlaylist(filtered);
};

function renderFilteredPlaylist(data) {
    const container = document.querySelector('.playlist-scroll');
    const lang = localStorage.getItem('selectedLanguage') || 'en';
    
    if (!container) return;
    
    container.innerHTML = data.map((story, index) => {
        const displayTitle = story.title[lang] || story.title['en'];
        
        // Instead of passing the whole object as a string, we pass the INDEX
        return `
            <div class="story-item" onclick="updatePreviewByIndex(${index})">
                <div class="thumb-wrap">
                    <img src="${story.thumbnail}" alt="${displayTitle}">
                </div>
                <div class="story-meta">
                    <span class="story-title">${displayTitle}</span>
                    <small class="story-subtitle">${story.speaker} | ${story.day}</small>
                </div>
            </div>
        `;
    }).join('');
}

window.updatePreviewByIndex = function(index) {
    // We use the current filtered list (you might need to store this globally)
    const typeVal = document.getElementById('filterType').value;
    const speakerVal = document.getElementById('filterSpeaker').value;
    const dayVal = document.getElementById('filterDay').value;

    const filtered = storiesData.filter(item => {
        const matchType = (typeVal === 'all' || item.type === typeVal);
        const matchSpeaker = (speakerVal === 'all' || item.speaker === speakerVal);
        const matchDay = (dayVal === 'all' || item.day === dayVal);
        return matchType && matchSpeaker && matchDay;
    });

    if (filtered[index]) {
        updatePreview(filtered[index]);
    }
};

window.updatePreviewByObject = function(storyStr) {
    const story = JSON.parse(storyStr.replace(/&quot;/g, '"').replace(/&apos;/g, "'"));
    updatePreview(story);
};

// MASTER FUNCTION: Updates the stage content
window.updatePreview = function(story) {
    currentStory = story;
    const lang = localStorage.getItem('selectedLanguage') || 'en';
    
    const titleEl = document.getElementById('stageTitle');
    const descEl = document.getElementById('stageDesc');
    const btn = document.getElementById('mainActionButton');
    const playerWrap = document.getElementById('newsPlayerWrap');
    const stageImg = document.getElementById('stageImage');

    const translatedTitle = story.title[lang] || story.title['en'];
    const translatedDesc = story.description[lang] || story.description['en'];

    titleEl.innerText = translatedTitle;
    descEl.innerText = translatedDesc;
    
    if (stageImg) stageImg.src = story.thumbnail;
    
    const playText = translations[lang]['stories.play_btn'] || 'PLAY VIDEO';
    const readText = translations[lang]['vkids.read'] || 'READ ARTICLE';
    btn.innerHTML = (story.type === 'video') ? `▶ ${playText}` : `📖 ${readText}`;
    
    // THE FIX: Stop player and clear tracks BEFORE hiding it
    const myPlayer = videojs.getPlayer('newsBrightcovePlayer');
    if (myPlayer) {
        myPlayer.pause();
        // Manually remove all tracks to prevent the 'kind' error
        const tracks = myPlayer.remoteTextTracks();
        if (tracks) {
            let i = tracks.length;
            while (i--) {
                myPlayer.removeRemoteTextTrack(tracks[i]);
            }
        }
    }

    if (playerWrap) playerWrap.style.display = 'none';
    if (stageImg) stageImg.style.display = 'block';
};

window.launchContent = function() {
    if (!currentStory) return;
    
    if (currentStory.type === 'video') {
        const playerWrap = document.getElementById('newsPlayerWrap');
        const stageImg = document.getElementById('stageImage');
        
        playerWrap.style.display = 'block';
        stageImg.style.display = 'none';

        const myPlayer = videojs.getPlayer('newsBrightcovePlayer');
        
        if (myPlayer) {
            myPlayer.catalog.getVideo(currentStory.id, function(error, video) {
                if (error) {
                    console.error("Catalog Error:", error);
                    return;
                }
                myPlayer.catalog.load(video);
                
                // Use 'one' to ensure this only fires once per load
                myPlayer.one('loadedmetadata', function() {
                    myPlayer.play().catch(e => console.warn("Auto-play blocked"));
                    myPlayer.trigger('resize');
                });
            });
        }
    } else if (currentStory.link) {
        window.open(currentStory.link, '_blank');
    }
};

window.closeVideo = function() {
    const playerWrap = document.getElementById('newsPlayerWrap');
    const stageImg = document.getElementById('stageImage');
    const myPlayer = videojs.getPlayer('newsBrightcovePlayer');
    
    if (playerWrap) playerWrap.style.display = 'none';
    if (stageImg) stageImg.style.display = 'block';
    if (myPlayer) myPlayer.pause();
};

window.closeVideoModalVKids = function() {
    const modal = document.getElementById('videoModal');
    const myPlayer = videojs.getPlayer('myBrightcovePlayer');
    
    if (modal) modal.style.display = 'none';
    if (myPlayer) myPlayer.pause();
};




window.adjustTitleSize = function() {
    const titleElement = document.getElementById('stageTitle');
    if (!titleElement) return;
    const isMobile = window.innerWidth <= 768;
    const len = titleElement.innerText.length;

    titleElement.style.fontSize = isMobile ? "1.1rem" : "1.4rem";
    if (len > 70) titleElement.style.fontSize = isMobile ? "0.9rem" : "1.1rem";
    else if (len > 45) titleElement.style.fontSize = isMobile ? "1rem" : "1.25rem";
};

