function renderVFAQs(lang) {
    const container = document.getElementById('faq-accordion');
    const faqItems = vFaqData['en'].questions;

    if (!container) return;

    container.innerHTML = faqItems.map((item, index) => {
        const question = item.q[lang] || item.q['en'];
        const answer = item.a[lang] || item.a['en'];

        return `
            <div class="faq-item" id="faq-item-${index}">
                <button class="faq-question" aria-expanded="false" onclick="toggleFaq(${index})">
                    <span>${question}</span>
                    <span class="faq-icon">+</span>
                </button>
                <div class="faq-answer">
                    <div class="faq-answer-content">
                        <p>${answer}</p>
                    </div>
                </div>
            </div>
        `;
    }).join('');
}

function toggleFaq(index) {
    const targetItem = document.getElementById(`faq-item-${index}`);
    const isActive = targetItem.classList.contains('active');
    
    // Optional: Close others for a clean accordion look
    document.querySelectorAll('.faq-item').forEach(item => {
        item.classList.remove('active');
        item.querySelector('.faq-question').setAttribute('aria-expanded', 'false');
    });
    
    // Toggle current
    if (!isActive) {
        targetItem.classList.add('active');
        targetItem.querySelector('.faq-question').setAttribute('aria-expanded', 'true');
    }
}


