// The Throttle Helper
function throttle(func, limit) {
    let inThrottle;
    return function() {
        const args = arguments;
        const context = this;
        if (!inThrottle) {
            func.apply(context, args);
            inThrottle = true;
            setTimeout(() => inThrottle = false, limit);
        }
    }
}

window.addEventListener('scroll', throttle(updateScrollSpy, 100));

// This works for any device, one JSON file
function renderContent(item, lang = 'en') {
    // 1. The Title
    // Try current lang -> Try English -> Fallback to "New Story"
    const title = item?.q?.[lang] || item?.q?.['en'] || "New Story";

    // 2. The Description
    // Try current lang -> Try English -> Fallback to empty string
    const desc = item?.a?.[lang] || item?.a?.['en'] || "";

    // Now inject them into the HTML
    document.getElementById('stageTitle').innerHTML = title;
    document.getElementById('stageDesc').innerHTML = desc;
}





